const b = $json.body || $json;
const required = ['lineUid','branchName','ownerName','tel','address','subdistrict','district','province','postalCode'];
const value = (key) => String(b[key] || '').trim();
const missing = required.filter((key) => !value(key));
if (missing.length) throw new Error(`ข้อมูลไม่ครบ: ${missing.join(', ')}`);
const tel = value('tel').replace(/[\s-]/g, '');
if (!/^\+?[0-9]{8,15}$/.test(tel)) throw new Error('เบอร์โทรศัพท์ไม่ถูกต้อง');
if (!/^\d{5}$/.test(value('postalCode'))) throw new Error('รหัสไปรษณีย์ต้องมี 5 หลัก');
const now = new Date();
const ymd = now.toISOString().slice(0,10).replace(/-/g,'');
const applicationId = `BA-${ymd}-${String(Math.floor(Math.random()*10000)).padStart(4,'0')}`;
return [{json:{Application_ID:applicationId,Submitted_At:b.submittedAt || now.toISOString(),LINE_UID:value('lineUid'),LINE_Display_Name:value('lineDisplayName'),Branch_Name:value('branchName'),Owner_Name:value('ownerName'),Tel:tel,Email:value('email'),Address:value('address'),Subdistrict:value('subdistrict'),District:value('district'),Province:value('province'),Postal_Code:value('postalCode'),Google_Map_URL:value('googleMapUrl'),Tax_ID:value('taxId'),Status:'Pending',Reviewed_At:'',Reviewed_By_UID:'',Reviewed_By_Name:'',Reject_Reason:''}}];

const application = $node['Validate Branch Application'].json;
const rows = $input.all().map(i => i.json);
const previous = rows.find(r => String(r.LINE_UID || '') === application.LINE_UID && ['Pending','Approved'].includes(String(r.Status || '')));
const canSubmit = !previous;
return [{json:{...application,canSubmit,response: canSubmit ? null : {success:false,message: previous.Status === 'Approved' ? 'บัญชีนี้ได้รับการอนุมัติแล้ว' : 'มีคำขอที่กำลังรอการตรวจสอบอยู่',applicationId:previous.Application_ID || ''}}}];
